/* OnlyOffice local socket bridge. The real network Socket.IO client is replaced by a parent-window scoped factory. */
(function(root, factory) {
  if (typeof exports === "object" && typeof module !== "undefined") {
    module.exports = factory();
  } else if (typeof define === "function" && define.amd) {
    define(factory);
  } else {
    root.io = factory();
  }
})(typeof globalThis !== "undefined" ? globalThis : this, function() {
  function getFrameEditorId() {
    try {
      return new URLSearchParams(window.location.search).get("frameEditorId") || "";
    } catch (error) {
      return "";
    }
  }

  function isSameOriginParent() {
    try {
      if (!window.parent || window.parent === window) {
        return true;
      }
      return window.parent.location.origin === window.location.origin;
    } catch (error) {
      return false;
    }
  }

  function bridgeIo(url, options) {
    var frameEditorId = getFrameEditorId();
    var factory = null;

    // CDN 跨域：禁止读 parent.__ONLYOFFICE_SCOPED_IO__（会 SecurityError），只用 iframe 内 registry。
    if (isSameOriginParent()) {
      var parentWindow = window.parent;
      var registry = parentWindow && parentWindow.__ONLYOFFICE_SCOPED_IO__;
      factory = registry && registry[frameEditorId];
    }

    if (!factory) {
      var selfRegistry = window.__ONLYOFFICE_SCOPED_IO__;
      factory = selfRegistry && selfRegistry[frameEditorId];
    }

    if (!factory) {
      throw new Error(
        "OnlyOffice scoped socket is not registered for " +
          frameEditorId +
          ". Load onlyoffice-cross-origin-bridge.js before socket.io on CDN.",
      );
    }

    return factory(url, options);
  }

  bridgeIo.io = bridgeIo;
  bridgeIo.connect = bridgeIo;
  bridgeIo.Manager = function Manager() {
    throw new Error("OnlyOffice local socket bridge does not support Manager");
  };

  return bridgeIo;
});
